import * as React from 'react';
import { Container, Typography, Paper, TextField, Button, Box } from '@mui/material';

export default function Login() {
  return (
    <Container maxWidth="sm" sx={{mt:6}}>
      <Paper elevation={3} sx={{p:4}}>
        <Typography variant="h4" gutterBottom>Đăng nhập</Typography>
        <Box component="form" sx={{display:'flex', flexDirection:'column', gap:2}}>
          <TextField label="Email" type="email" required fullWidth />
          <TextField label="Mật khẩu" type="password" required fullWidth />
          <Button variant="contained" color="primary" sx={{mt:2}}>Đăng nhập</Button>
        </Box>
      </Paper>
    </Container>
  );
}
